public class TestBooleanAttribute {
    public static void main(String[] args) {
        // Parse HTML element "<div hidden>"
        Element element = Jsoup.parse("<div hidden>").select("div").first();
        System.out.println("Element: " + element);

        // Get the attributes
        Attributes attributes = element.attributes();
        System.out.println("Attributes: " + attributes);

        // Iterate through attributes to find the hidden attribute
        for (Attribute attr : attributes) {
            System.out.println("Attribute key: " + attr.getKey() + ", value: " + attr.getValue());
            System.out.println("Value is null: " + (attr.getValue() == null));
            if (attr.getValue() == null) {
                System.out.println("Attribute value is null for key: " + attr.getKey());
            } else {
                System.out.println("Attribute value is: '" + attr.getValue() + "'");
            }
        }
    }
